      {:ok, doc} ->
        try do
          result = SweetXml.xpath(doc, xpath_expr)
          {:ok, result}
        rescue
          e -> {:error, "XPath evaluation failed: #{inspect(e)}"}
        end

      {:error, _} = error ->
        error
    end
  end

  @doc """
  Safely parse and extract multiple values using xmap.
  """
  def safe_xmap(xml_string, mapping) do
    case safe_parse(xml_string) do
      {:ok, doc} ->
        try do
          result = SweetXml.xmap(doc, mapping)
          {:ok, result}
        rescue
          e -> {:error, "XPath mapping failed: #{inspect(e)}"}
        end

      {:error, _} = error ->
        error
    end
  end

  @doc """
  Strips any DOCTYPE declarations from XML to prevent entity expansion attacks.
  This is an additional defense-in-depth measure.
  """
  def sanitize_xml(xml_string) do
